import sys

input = sys.stdin.readline

def check_possible(a, b):
    if len(a) != len(b):
        return False
    for i in range(len(a)):
        if a[i] == b[i]:
            continue
        else:
            return False
    return True


def solve(n, a, s):
    # Your code here
    if n == 1:
        return True
    for i in range(n - 1):
        if s[i] == '0':
            continue
        else:
            if a[i] > a[i + 1]:
                a[i], a[i + 1] = a[i + 1], a[i]
    return check_possible(sorted(a), a)


def main():
    n = int(input())
    a = list(map(int, input().split()))
    s = input().strip()
    print("YES" if solve(n, a, s) else "NO")


if __name__ == "__main__":
    main()
